solution_code:
#include <iostream>

struct Tracked {
    int val;
    static int s_copies;

    Tracked(int v) : val{v} {}
    Tracked(const Tracked& other) : val{other.val} {
        ++s_copies;
    }
};
int Tracked::s_copies = 0;

int howManyCopies() {
    int count = Tracked::s_copies;
    Tracked::s_copies = 0;
    return count;
}

int main() {
    int n;
    std::cin >> n;
    for (int i = 0; i < n; ++i) {
        int v;
        std::cin >> v;
        Tracked t{v};
        Tracked u = t;
        std::cout << "val=" << u.val << " copies=" << howManyCopies() << "\n";
    }
}

