#include <iostream>

struct Point {
    int x;
    int y;
    Point(int px, int py) : x{px}, y{py} {}
};

Point makePoint(int x, int y) {
    return Point{x, y};
}

int main() {
    int n;
    std::cin >> n;
    for (int i = 0; i < n; ++i) {
        int x, y;
        std::cin >> x >> y;
        Point p = makePoint(x, y);
        std::cout << "(" << p.x << ", " << p.y << ")\n";
    }
}
